<?php
 namespace FilesManager; class Thumbnail { private string $cacheDir; private int $width; private int $height; private int $quality; public function __construct( string $cacheDir, int $width = 200, int $height = 200, int $quality = 80 ) { $this->cacheDir = $cacheDir; $this->width = $width; $this->height = $height; $this->quality = $quality; if (!is_dir($this->cacheDir)) { mkdir($this->cacheDir, 0755, true); } } public function generate(string $imagePath): string|false { if (!file_exists($imagePath) || !is_file($imagePath)) { return false; } $isImage = $this->isImage($imagePath); $isVideo = $this->isVideo($imagePath); if (!$isImage && !$isVideo) { return false; } $cacheFile = $this->getCacheFilename($imagePath); if (file_exists($cacheFile) && filemtime($cacheFile) >= filemtime($imagePath)) { return $cacheFile; } if ($isImage) { $success = $this->createThumbnail($imagePath, $cacheFile); } else { $success = $this->createVideoThumbnail($imagePath, $cacheFile); if (!$success) { $success = $this->createGenericVideoThumbnail($cacheFile); } } return $success ? $cacheFile : false; } private function isImage(string $filePath): bool { $mime = mime_content_type($filePath); return strpos($mime, 'image/') === 0; } private function isVideo(string $filePath): bool { $mime = mime_content_type($filePath); return strpos($mime, 'video/') === 0; } private function getCacheFilename(string $imagePath): string { $hash = md5($imagePath . filemtime($imagePath)); return $this->cacheDir . '/' . $hash . '.jpg'; } private function createThumbnail(string $source, string $destination): bool { $imageInfo = getimagesize($source); if ($imageInfo === false) { return false; } $srcWidth = $imageInfo[0]; $srcHeight = $imageInfo[1]; $mimeType = $imageInfo['mime']; $srcImage = $this->createImageFromFile($source, $mimeType); if ($srcImage === false) { return false; } $ratio = min($this->width / $srcWidth, $this->height / $srcHeight); $newWidth = (int)($srcWidth * $ratio); $newHeight = (int)($srcHeight * $ratio); $dstImage = imagecreatetruecolor($newWidth, $newHeight); if ($mimeType === 'image/png' || $mimeType === 'image/gif') { imagealphablending($dstImage, false); imagesavealpha($dstImage, true); $transparent = imagecolorallocatealpha($dstImage, 255, 255, 255, 127); imagefilledrectangle($dstImage, 0, 0, $newWidth, $newHeight, $transparent); } imagecopyresampled( $dstImage, $srcImage, 0, 0, 0, 0, $newWidth, $newHeight, $srcWidth, $srcHeight ); $success = imagejpeg($dstImage, $destination, $this->quality); imagedestroy($srcImage); imagedestroy($dstImage); return $success; } private function createImageFromFile(string $filePath, string $mimeType): \GdImage|false { return match ($mimeType) { 'image/jpeg' => imagecreatefromjpeg($filePath), 'image/png' => imagecreatefrompng($filePath), 'image/gif' => imagecreatefromgif($filePath), 'image/webp' => imagecreatefromwebp($filePath), default => false, }; } private function createVideoThumbnail(string $source, string $destination): bool { $ffmpegPath = $this->findFFmpeg(); if (!$ffmpegPath) { return false; } $escapedSource = escapeshellarg($source); $escapedDest = escapeshellarg($destination); $command = sprintf( '%s -ss 00:00:01 -i %s -vframes 1 -vf "scale=%d:%d:force_original_aspect_ratio=decrease" -q:v %d %s 2>&1', $ffmpegPath, $escapedSource, $this->width, $this->height, (int)(31 - ($this->quality * 0.31)), $escapedDest ); exec($command, $output, $returnCode); return $returnCode === 0 && file_exists($destination); } private function createGenericVideoThumbnail(string $destination): bool { $image = imagecreatetruecolor($this->width, $this->height); if (!$image) { return false; } $bgColor = imagecolorallocate($image, 45, 45, 45); $iconColor = imagecolorallocate($image, 200, 200, 200); $textColor = imagecolorallocate($image, 180, 180, 180); imagefilledrectangle($image, 0, 0, $this->width, $this->height, $bgColor); $centerX = $this->width / 2; $centerY = $this->height / 2; $size = min($this->width, $this->height) * 0.3; $triangle = [ $centerX - $size * 0.4, $centerY - $size * 0.5, $centerX - $size * 0.4, $centerY + $size * 0.5, $centerX + $size * 0.6, $centerY ]; imagefilledpolygon($image, $triangle, $iconColor); $text = 'VIDEO'; $fontSize = 3; $textWidth = imagefontwidth($fontSize) * strlen($text); $textX = ($this->width - $textWidth) / 2; $textY = $this->height - 20; imagestring($image, $fontSize, (int)$textX, (int)$textY, $text, $textColor); $success = imagejpeg($image, $destination, $this->quality); imagedestroy($image); return $success; } private function findFFmpeg(): string|false { $paths = [ 'ffmpeg', '/usr/bin/ffmpeg', '/usr/local/bin/ffmpeg', '/opt/homebrew/bin/ffmpeg', ]; foreach ($paths as $path) { exec("command -v $path 2>&1", $output, $returnCode); if ($returnCode === 0) { return $path; } } return false; } public function cleanCache(int $maxAge = 2592000): int { $count = 0; $now = time(); $files = glob($this->cacheDir . '/*.jpg'); foreach ($files as $file) { if ($now - filemtime($file) > $maxAge) { if (unlink($file)) { $count++; } } } return $count; } } 